public String tablecell(String content, TableCellFlags flags){
    String cellType;
    if(flags.isHeader()){
        cellType = "th";
    } else {
        cellType = "td";
    }

    if(content.length() == 0){
        content = "&nbsp;";
    }

    String align = flags.getAlign();
    if(align != null){
        return "<" + cellType + " style=\"text-align: " + align + "\">" + content + "</" + cellType + ">\n";
    } else {
        return "<" + cellType + ">" + content + "</" + cellType + ">\n";
    }
}

